}

package org.apache.commons.collections.map.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.apache.commons.collections.map.MultiValueMap;
import static org.junit.Assert.*;

public class StepDefs {
    private MultiValueMap map;
    private Object putResult;

    @Given("I have a MultiValueMap")
    public void i_have_a_MultiValueMap() {
        map = new MultiValueMap();
    }

    @When("I put the key {string} with value {string}")
    public void i_put_the_key_with_value(String key, String value) {
        try {
            putResult = map.put(key, value);
        } catch (Exception e) {
            putResult = e; // Capture exception if it occurs
        }
    }

    @Then("the put operation should return {string}")
    public void the_put_operation_should_return(String expectedValue) {
        assertEquals(expectedValue, putResult);
    }

    @Then("the map should contain {int} value for key {string}")
    public void the_map_should_contain_value_for_key(Integer expectedCount, String key) {
        Object values = map.get(key);
        int actualCount = 0;

        if (values != null) {
            if (values instanceof java.util.Collection) {
                actualCount = ((java.util.Collection<?>) values).size();
            } else {
                actualCount = 1; // Single value
            }
        }

        assertEquals(expectedCount.intValue(), actualCount);
    }

    @Then("the total size of the map should be {int}")
    public void the_total_size_of_the_map_should_be(Integer expectedSize) {
        int actualSize = 0;

        for (Object key : map.keySet()) {
            Object values = map.get(key);
            if (values instanceof java.util.Collection) {
                actualSize += ((java.util.Collection<?>) values).size();
            } else {
                actualSize += 1; // Single value
            }
        }

        assertEquals(expectedSize.intValue(), actualSize);
    }

    @Given("I put the key {string} with value {string}")
    public void given_i_put_the_key_with_value(String key, String value) {
        try {
            map.put(key, value);
        } catch (Exception e) {
            // Handle exception if needed
        }
    }
}

